-- Fail before permanent writes if the embedded source snapshot differs from the approved totals.
do $verify$
declare
  v_rows integer;
  v_codes integer;
  v_cases integer;
  v_partially_effective integer;
  v_not_exists integer;
  v_2026_09_30 integer;
  v_2026_12_31 integer;
  v_2027_06_30 integer;
begin
  select count(*), count(distinct code), count(distinct case_id),
         count(*) filter (where assessment_rating = 'partially_effective'),
         count(*) filter (where assessment_rating = 'not_exists'),
         count(*) filter (where target_date = date '2026-09-30'),
         count(*) filter (where target_date = date '2026-12-31'),
         count(*) filter (where target_date = date '2027-06-30')
    into v_rows, v_codes, v_cases, v_partially_effective, v_not_exists,
         v_2026_09_30, v_2026_12_31, v_2027_06_30
  from financial_control_seed_stage;

  if v_rows <> 33 or v_codes <> 33 or v_cases <> 33 then
    raise exception 'Seed verification failed: rows=%, unique codes=%, unique case_ids=%', v_rows, v_codes, v_cases;
  end if;
  if v_partially_effective <> 19 or v_not_exists <> 14 then
    raise exception 'Seed verification failed: partially_effective=%, not_exists=%', v_partially_effective, v_not_exists;
  end if;
  if v_2026_09_30 <> 2 or v_2026_12_31 <> 3 or v_2027_06_30 <> 28 then
    raise exception 'Seed verification failed: due dates are %, %, %', v_2026_09_30, v_2026_12_31, v_2027_06_30;
  end if;
  if not exists (
    select 1 from financial_control_seed_stage
    where code = '1.6'
      and responsible_unit = 'وحدة إدارة المخاطر واستمرارية الأعمال'
      and official_responsible_unit = 'وحدة إدارة المخاطر واستمرارية الأعمال'
  ) then
    raise exception 'Seed verification failed: finding 1.6 owner is not the approved official unit';
  end if;
  if exists (
    select 1 from financial_control_seed_stage
    where not source_html_verified
       or not source_pdf_verified
       or requires_manual_review
       or nullif(btrim(official_title), '') is null
       or nullif(btrim(official_finding_text), '') is null
       or nullif(btrim(control_or_standard), '') is null
       or nullif(btrim(official_recommendation), '') is null
       or nullif(btrim(official_responsible_unit), '') is null
  ) then
    raise exception 'Seed verification failed: at least one record lacks verified official content';
  end if;
  if (select count(*) from public.workspaces where code = 'financial-control') <> 1 then
    raise exception 'Seed verification failed: exactly one financial-control workspace is required';
  end if;
end;
$verify$;

insert into public.financial_control_source_documents (
  workspace_id, document_type, file_name, document_version,
  checksum, is_authoritative, metadata
)
select
  w.id, 'official_report', 'تقرير تقييم مستوى الكفاءة الرقابية - الأمانة العامة للمجلس الصحي السعودي.pdf', 'verified-import-review-v1',
  'B043F64774EDA97C29B6911D42110C06B35BCF64F09B487B4AA69B50C44CD4A4', true,
  jsonb_build_object(
    'expected_findings', 33,
    'source_json', 'data/financial-control/findings_import_review.json',
    'source_validation_report', 'docs/financial-control/IMPORT_VALIDATION_REPORT_VERIFIED.md'
  )
from public.workspaces w
where w.code = 'financial-control'
on conflict (workspace_id, document_type, file_name, document_version) do nothing;

-- Reject collisions instead of silently joining a code to a different case_id.
do $collisions$
declare
  v_workspace_id uuid;
begin
  select id into strict v_workspace_id
  from public.workspaces
  where code = 'financial-control';

  if exists (
    select 1
    from financial_control_seed_stage s
    join public.financial_control_findings f
      on f.workspace_id = v_workspace_id
     and (f.reference_code = s.code or f.case_code = s.case_id)
    where f.reference_code is distinct from s.code
       or f.case_code is distinct from s.case_id
  ) then
    raise exception 'Seed collision: an existing code or case_id maps to a different record';
  end if;
end;
$collisions$;

with target as (
  select w.id as workspace_id, d.id as source_document_id
  from public.workspaces w
  join public.financial_control_source_documents d
    on d.workspace_id = w.id
   and d.document_type = 'official_report'
   and d.file_name = 'تقرير تقييم مستوى الكفاءة الرقابية - الأمانة العامة للمجلس الصحي السعودي.pdf'
   and d.document_version = 'verified-import-review-v1'
  where w.code = 'financial-control'
), inserted as (
  insert into public.financial_control_findings (
    workspace_id, source_document_id, sequence_no, case_code, reference_code,
    report_page, title, assessment_rating, assessment_rating_label,
    control_reference, control_summary, official_finding_text, official_risk_impact,
    official_owner_label, imported_owner_alias, official_due_date, official_quarter,
    workflow_status, progress_percent, current_due_date
  )
  select
    t.workspace_id, t.source_document_id, s.sequence_no, s.case_id, s.code,
    s.pdf_reference_page, s.official_title, s.assessment_rating, s.assessment_rating_label,
    s.control_or_standard, s.control_or_standard, s.official_finding_text, s.official_finding_text,
    s.official_responsible_unit, s.responsible_unit_html_value, s.target_date, s.target_quarter,
    'imported_pending_review', 0, s.target_date
  from financial_control_seed_stage s
  cross join target t
  where not exists (
    select 1 from public.financial_control_findings f
    where f.workspace_id = t.workspace_id
      and (f.reference_code = s.code or f.case_code = s.case_id)
  )
  returning *
)
insert into public.audit_logs (
  actor_user_id, table_name, record_id, action, old_data, new_data, created_at
)
select
  null, 'financial_control_findings', i.id::text, 'INSERT', null,
  to_jsonb(i) || jsonb_build_object('_seed_source', 'findings_import_review_v1'),
  clock_timestamp()
from inserted i;

-- Add one corrective action only when the verified corrective_plan is present.
with inserted as (
  insert into public.corrective_actions (
    workspace_id, finding_id, action_no, official_action_text,
    official_due_date, current_due_date, workflow_status, progress_percent
  )
  select
    f.workspace_id, f.id, 1, s.corrective_plan,
    s.target_date, s.target_date, 'not_started', 0
  from financial_control_seed_stage s
  join public.workspaces w on w.code = 'financial-control'
  join public.financial_control_findings f
    on f.workspace_id = w.id
   and f.reference_code = s.code
  where nullif(btrim(s.corrective_plan), '') is not null
    and not exists (
      select 1 from public.corrective_actions ca
      where ca.finding_id = f.id and ca.action_no = 1
    )
  returning *
)
insert into public.audit_logs (
  actor_user_id, table_name, record_id, action, old_data, new_data, created_at
)
select
  null, 'corrective_actions', i.id::text, 'INSERT', null,
  to_jsonb(i) || jsonb_build_object('_seed_source', 'findings_import_review_v1'),
  clock_timestamp()
from inserted i;

-- Verify the resulting database state. Any mismatch rolls back the whole transaction.
do $result$
declare
  v_workspace_id uuid;
  v_findings integer;
  v_expected_actions integer;
  v_actions integer;
  v_finding_audits integer;
  v_action_audits integer;
begin
  select id into strict v_workspace_id
  from public.workspaces
  where code = 'financial-control';

  select count(*) into v_findings
  from financial_control_seed_stage s
  join public.financial_control_findings f
    on f.workspace_id = v_workspace_id
   and f.reference_code = s.code
   and f.case_code = s.case_id;

  select count(*) into v_expected_actions
  from financial_control_seed_stage
  where nullif(btrim(corrective_plan), '') is not null;

  select count(*) into v_actions
  from financial_control_seed_stage s
  join public.financial_control_findings f
    on f.workspace_id = v_workspace_id and f.reference_code = s.code
  join public.corrective_actions ca
    on ca.finding_id = f.id
   and ca.action_no = 1
   and ca.official_action_text = s.corrective_plan
  where nullif(btrim(s.corrective_plan), '') is not null;

  select count(*) into v_finding_audits
  from financial_control_seed_stage s
  join public.financial_control_findings f
    on f.workspace_id = v_workspace_id and f.reference_code = s.code
  join public.audit_logs a
    on a.table_name = 'financial_control_findings'
   and a.record_id = f.id::text
   and a.action = 'INSERT'
   and a.new_data ->> '_seed_source' = 'findings_import_review_v1';

  select count(*) into v_action_audits
  from financial_control_seed_stage s
  join public.financial_control_findings f
    on f.workspace_id = v_workspace_id and f.reference_code = s.code
  join public.corrective_actions ca
    on ca.finding_id = f.id and ca.action_no = 1
  join public.audit_logs a
    on a.table_name = 'corrective_actions'
   and a.record_id = ca.id::text
   and a.action = 'INSERT'
   and a.new_data ->> '_seed_source' = 'findings_import_review_v1'
  where nullif(btrim(s.corrective_plan), '') is not null;

  if v_findings <> 33 then
    raise exception 'Seed result verification failed: expected 33 findings, got %', v_findings;
  end if;
  if v_actions <> v_expected_actions then
    raise exception 'Seed result verification failed: expected % corrective actions, got %', v_expected_actions, v_actions;
  end if;
  if v_finding_audits <> 33 or v_action_audits <> v_expected_actions then
    raise exception 'Seed result verification failed: finding audits=%, action audits=%', v_finding_audits, v_action_audits;
  end if;
end;
$result$;

commit;
